function GoogleAnalytics() {
  return (
    <>
      <Script
        src={`https://www.googletagmanager.com/gtag/js?id=${GA_MEASUREMENT_ID}`}
        strategy="afterInteractive"
      />
      <Script id="google-analytics" strategy="afterInteractive">
        {`
          window.dataLayer = window.dataLayer || [];
          function gtag(){dataLayer.push(arguments);}
          gtag('js', new Date());
          gtag('config', '${GA_MEASUREMENT_ID}');
        `}
      </Script>
    </>
  )
}

function VisitSourceButton({
  url,
  title,
  city,
  sourceDomain,
  category,
}: VisitSourceButtonProps) {
  const handleClick = () => {
    // Analytics (existing)
    if (typeof window !== "undefined" && window.gtag) {
      window.gtag("event", "visit_source", {
        event_category: "engagement",
        event_label: title,
        city,
        source_domain: sourceDomain,
      })
    }

    // Fire-and-forget preference tracking (does not block navigation)
    if (category) {
      try {
        fetch("/api/preferences/track", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ category, city }),
          keepalive: true,
        }).catch(() => {
          // Ignore - anonymous users will get 401, non-critical
        })
      } catch {
        // Ignore
      }
    }
  }

  return (
    <a
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      onClick={handleClick}
      className="block"
    >
      <Button size="lg" className="w-full gap-2 text-base font-semibold">
        Visit Source
        <ExternalLink className="h-4 w-4" />
      </Button>
    </a>
  )
}
